const processPurchaseReturn = async (poNumbers) => {
    const resPO = await Promise.all(
        poNumbers.map(poId => db.collection('purchase_order').doc(poId).get())
    );
    console.log('Purchase orders:', resPO);

    const poData = resPO.map(response => response.data[0]);
    console.log('Purchase order data:', poData);

    const displayText = poData
        .map(po => po?.purchase_order_no)
        .filter(Boolean)
        .join(', ');

    this.setData({'po_no_display': displayText});

    let tablePRT = [];

    // Create an array to hold all our promises
    const promises = [];

    // Process each PO
    for (const po of poData) {
        const poLineItemData = po.table_po || [];
        console.log('poLineItemData for PO:', po.purchase_order_no, poLineItemData);

        // Process each line item
        if (poLineItemData.length > 0) {
            // Create a promise for each line item and add to our promises array
            poLineItemData.forEach(poItem => {
                promises.push((async () => {
                    console.log("Processing PO item:", poItem);

                    const resItem = await db.collection("Item").where({ id: poItem.item_id }).get();
                    const itemData = resItem?.data[0];

                    const prtItemData = {
                        material_id: poItem.item_id,
                        material_name: poItem.item_name,
                        material_desc: poItem.item_desc || "",
                        more_desc: poItem.more_desc || '',
                        line_remark_1: poItem.line_remark_1 || '',
                        line_remark_2: poItem.line_remark_2 || '',
                        po_number: po.purchase_order_no,
                        po_date: po.po_date,
                        received_qty: parseFloat(poItem.received_qty || 0),
                        return_uom_id: poItem.quantity_uom,
                        unit_price: poItem.unit_price,
                        total_price: poItem.po_amount,
                        returned_quantity: poItem.return_quantity || 0,
                        costing_method: itemData.material_costing_method,
                    };

                    tablePRT.push(prtItemData);
