(async () => {
  const data = this.getValues();
  const temporaryData = data.confirm_inventory.table_item_balance;
  const rowIndex = data.confirm_inventory.row_index;
  const returnQty = data.confirm_inventory.received_qty;
  let isValid = true;
  // Get UOM information (you'll need to add this based on your data structure)
  const materialUOMid = data.confirm_inventory.material_uom; // Adjust field name as needed
  const gdUOM = await db
    .collection("unit_of_measurement")
    .where({ id: materialUOMid })
    .get()
    .then((res) => {
      return res.data[0]?.uom_name || "PCS"; // Default to PCS if not found
    });

  // Check if all rows have passed validation
  const allValid = temporaryData.every((item, idx) => {
    const isValid =
      window.validationState && window.validationState[idx] !== false;
    console.log(`Row ${idx} validation: ${isValid}`);
    return isValid;
  });

  if (!allValid) {
    console.log("Validation failed, canceling confirm");
    return;
  }

  let totalReturnQty = temporaryData.reduce((sum, item) => {
    const category_type = item.inventory_category || null;

    if (item.return_quantity > 0) {
      if (category_type === null) isValid = false;
    }
    return sum + (item.return_quantity || item.prt_quantity || 0);
  }, 0);

  if (isValid) {
    if (totalReturnQty > returnQty) {
      this.$message.error(
        "Total return quantity cannot exceed return quantity."
      );
      return;
    } else {
      const filteredData = temporaryData.filter((item) => {
        const qty = item.return_quantity || item.prt_quantity || 0;
        return qty !== null && qty !== undefined && qty !== 0;
      });

      const formatFilteredData = async (filteredData) => {
        // Get unique location IDs
        const locationIds = [
          ...new Set(filteredData.map((item) => item.location_id)),
        ];

        // Get unique batch IDs (filter out null/undefined values)
        const batchIds = [
          ...new Set(
            filteredData
              .map((item) => item.batch_id)
              .filter((batchId) => batchId != null && batchId !== "")
          ),
        ];

        // Fetch locations in parallel
        const locationPromises = locationIds.map(async (locationId) => {
          try {
            const resBinLocation = await db
              .collection("bin_location")
              .where({ id: locationId })
              .get();

            return {
              id: locationId,
              name:
                resBinLocation.data?.[0]?.bin_location_combine ||
                `Location ID: ${locationId}`,
            };
          } catch (error) {
            console.error(`Error fetching location ${locationId}:`, error);
            return { id: locationId, name: `${locationId} (Error)` };
          }
        });

        // Fetch batches in parallel (only if there are batch IDs)
        const batchPromises = batchIds.map(async (batchId) => {
          try {
            const resBatch = await db
              .collection("batch")
              .where({ id: batchId })
              .get();

            return {
              id: batchId,
              name: resBatch.data?.[0]?.batch_number || `Batch ID: ${batchId}`,
            };
          } catch (error) {
            console.error(`Error fetching batch ${batchId}:`, error);
            return { id: batchId, name: `${batchId} (Error)` };
          }
        });

        // Wait for both location and batch data
        const [locations, batches] = await Promise.all([
          Promise.all(locationPromises),
          Promise.all(batchPromises),
        ]);

        // Fixed category mapping - should be an object, not array of objects
        const categoryMap = {
          Blocked: "BLK",
          Reserved: "RES",
          Unrestricted: "UNR",
          "Quality Inspection": "QIP",
          "In Transit": "INT",
        };

        // Create lookup maps
        const locationMap = locations.reduce((map, loc) => {
          map[loc.id] = loc.name;
          return map;
        }, {});

        const batchMap = batches.reduce((map, batch) => {
          map[batch.id] = batch.name;
          return map;
        }, {});

        const totalQty = filteredData.reduce(
          (sum, item) => sum + (item.return_quantity || item.prt_quantity || 0),
          0
        );

        let summary = `Total: ${totalQty} ${gdUOM}\n\nDETAILS:\n`;

        const details = filteredData
          .map((item, index) => {
            const locationName =
              locationMap[item.location_id] || item.location_id;
            const qty = item.return_quantity || item.prt_quantity || 0;

            const categoryAbbr =
              categoryMap[item.inventory_category] ||
              categoryMap[item.category] ||
              item.inventory_category ||
              item.category ||
              "";

            let itemDetail = `${
              index + 1
            }. ${locationName}: ${qty} ${gdUOM} (${categoryAbbr})`;

            // Add serial number info if it exists (for serialized items)
            if (item.serial_number) {
              itemDetail += `\n[Serial: ${item.serial_number}]`;
            }

            // Add batch info on a new line if batch exists
            if (item.batch_id) {
              const batchName = batchMap[item.batch_id] || item.batch_id;
              itemDetail += `\n[${batchName}]`;
            }

            // Add remarks if available
            if (item.remarks && item.remarks.trim() !== "") {
              itemDetail += `\n[Remarks: ${item.remarks.trim()}]`;
            }

            return itemDetail;
          })
          .join("\n");

        return summary + details;
      };

      const formattedString = await formatFilteredData(filteredData);
      console.log("📋 Formatted string:", formattedString);

      // Continue with the original logic if validation passed
      const textareaContent = JSON.stringify(filteredData);

      this.setData({
        [`table_prt.${rowIndex}.temp_qty_data`]: textareaContent,
        [`table_prt.${rowIndex}.return_summary`]: formattedString,
      });

      this.setData({
        [`confirm_inventory.table_item_balance`]: [],
      });

      console.log("Input data:", temporaryData);
      console.log("Row index:", rowIndex);

      const totalCategoryQuantity = temporaryData.reduce(
        (sum, item) => sum + (item.return_quantity || item.prt_quantity || 0),
        0
      );
      console.log("Total category quantity:", totalCategoryQuantity);

      // Store the total in the form
      this.setData({
        [`table_prt.${rowIndex}.return_quantity`]: totalCategoryQuantity,
      });

      this.closeDialog("confirm_inventory");
    }
  }
})();

const updateInventory = async (data, plantId, organizationId) => {
  const items = data.table_prt;

  // Helper function to check if item is serialized
  const isSerializedItem = (materialData) => {
    return materialData && materialData.serial_number_management === 1;
  };

  // Helper function to parse balance index for serial numbers
  const parseBalanceIndexForSerials = (balanceIndexData) => {
    return balanceIndexData.filter(
      (balance) =>
        balance.serial_number &&
        balance.serial_number.trim() !== "" &&
        (balance.return_quantity || balance.prt_quantity) > 0,
    );
  };

  // Update FIFO inventory
  const updateFIFOInventory = async (
    materialId,
    returnQty,
    batchId,
    plantId,
  ) => {
    try {
      // Get all FIFO records for this material sorted by sequence (oldest first)
      const query = batchId
        ? db.collection("fifo_costing_history").where({
            material_id: materialId,
            batch_id: batchId,
            plant_id: plantId,
          })
        : db
            .collection("fifo_costing_history")
            .where({ material_id: materialId, plant_id: plantId });

      const response = await query.get();

      const result = response.data;

      if (result && Array.isArray(result) && result.length > 0) {
        // Sort by FIFO sequence (lowest/oldest first)
        const sortedRecords = result.sort(
          (a, b) => a.fifo_sequence - b.fifo_sequence,
        );

        let remainingQtyToDeduct = roundQty(returnQty);
        console.log(
          `Need to deduct ${remainingQtyToDeduct} units from FIFO inventory for material ${materialId}`,
        );

        // Process each FIFO record in sequence until we've accounted for all return quantity
        for (const record of sortedRecords) {
          if (remainingQtyToDeduct <= 0) {
            break;
          }

          const availableQty = roundQty(record.fifo_available_quantity || 0);
          console.log(
            `FIFO record ${record.fifo_sequence} has ${availableQty} available`,
          );

          // Calculate how much to take from this record
          const qtyToDeduct = Math.min(availableQty, remainingQtyToDeduct);
          const newAvailableQty = roundQty(availableQty - qtyToDeduct);

          console.log(
            `Deducting ${qtyToDeduct} from FIFO record ${record.fifo_sequence}, new available: ${newAvailableQty}`,
          );

          // Update this FIFO record
          await db.collection("fifo_costing_history").doc(record.id).update({
            fifo_available_quantity: newAvailableQty,
          });

          // Reduce the remaining quantity to deduct
          remainingQtyToDeduct = roundQty(remainingQtyToDeduct - qtyToDeduct);
        }

        if (remainingQtyToDeduct > 0) {
          console.warn(
            `Warning: Couldn't fully satisfy FIFO deduction for material ${materialId}. Remaining qty: ${remainingQtyToDeduct}`,
          );
        }
      } else {
        console.warn(`No FIFO records found for material ${materialId}`);
      }
    } catch (error) {
      console.error(
        `Error updating FIFO inventory for material ${materialId}:`,
        error,
      );
      throw error;
    }
  };

  const updateWeightedAverage = (item, returnQty, batchId, plantId) => {
    // Input validation
    if (
      !item ||
      !item.material_id ||
      isNaN(parseFloat(returnQty)) ||
      parseFloat(returnQty) <= 0
    ) {
      console.error("Invalid item data for weighted average update:", item);
      return Promise.resolve();
    }

    const query = batchId
      ? db.collection("wa_costing_method").where({
          material_id: item.material_id,
          batch_id: batchId,
          plant_id: plantId,
        })
      : db
          .collection("wa_costing_method")
          .where({ material_id: item.material_id, plant_id: plantId });

    return query
      .get()
      .then((waResponse) => {
        const waData = waResponse.data;

        if (!waData || !Array.isArray(waData) || waData.length === 0) {
          console.warn(
            `No weighted average records found for material ${item.material_id}`,
          );
          return Promise.resolve();
        }

        // Sort by date (newest first) to get the latest record
        waData.sort((a, b) => {
          if (a.created_at && b.created_at) {
            return new Date(b.created_at) - new Date(a.created_at);
          }
          return 0;
        });

        const waDoc = waData[0];
        const waCostPrice = roundPrice(waDoc.wa_cost_price || 0);
        const waQuantity = roundQty(waDoc.wa_quantity || 0);

        if (waQuantity <= returnQty) {
          console.warn(
            `Warning: Cannot fully update weighted average for ${item.material_id} - ` +
              `Available: ${waQuantity}, Requested: ${returnQty}`,
          );

          if (waQuantity <= 0) {
            return Promise.resolve();
          }
        }

        const newWaQuantity = Math.max(0, roundQty(waQuantity - returnQty));

        // If new quantity would be zero, handle specially
        if (newWaQuantity === 0) {
          return db
            .collection("wa_costing_method")
            .doc(waDoc.id)
            .update({
              wa_quantity: 0,
              updated_at: new Date(),
            })
            .then(() => {
              console.log(
                `Updated Weighted Average for item ${item.material_id} to zero quantity`,
              );
              return Promise.resolve();
            });
        }

        // const calculatedWaCostPrice = roundPrice(
        //   (waCostPrice * waQuantity - waCostPrice * returnQty) / newWaQuantity
        // );

        return db
          .collection("wa_costing_method")
          .doc(waDoc.id)
          .update({
            wa_quantity: newWaQuantity,
            wa_cost_price: waCostPrice,
            updated_at: new Date(),
          })
          .then(() => {
            console.log(
              `Successfully processed Weighted Average for item ${item.material_id}, ` +
                `new quantity: ${newWaQuantity}, new cost price: ${waCostPrice}`,
            );
            return Promise.resolve();
          });
      })
      .catch((error) => {
        console.error(
          `Error processing Weighted Average for item ${
            item?.material_id || "unknown"
