    } catch (error) {
      console.error(
        `Error creating serial movement record for ${serialNumber}:`,
        error,
      );
      throw error;
    }
  };

  // Main function to process serialized item returns
  const processSerializedItemReturn = async (
    item,
    materialData,
    balanceIndexData,
    plant_id,
    organization_id,
    allData,
  ) => {
    console.log(
      `Processing serialized item ${item.material_id} with ${balanceIndexData.length} serial balances`,
    );

    const serialBalances = parseBalanceIndexForSerials(balanceIndexData);

    if (serialBalances.length === 0) {
      console.log(
        `No serial numbers found for serialized item ${item.material_id}`,
      );
      return;
    }

    // Calculate total return quantity for costing updates
    let totalReturnQuantity = 0;

    for (const balance of serialBalances) {
      const returnQuantity = balance.return_quantity || balance.prt_quantity;
      totalReturnQuantity += returnQuantity;
    }

    console.log(
      `Serialized item ${item.material_id} total return quantity: ${totalReturnQuantity}`,
    );

    // Update costing methods (WA/FIFO) for serialized items
    if (totalReturnQuantity > 0) {
      try {
        console.log(
          `Updating costing for serialized item ${item.material_id}, return quantity: ${totalReturnQuantity}`,
        );

        const costingMethod = materialData.material_costing_method;
        const batchId =
          materialData.item_batch_management == "1" ? item.batch_id : null;

        if (costingMethod === "First In First Out") {
          await updateFIFOInventory(
            item.material_id,
            totalReturnQuantity,
            batchId,
            plant_id,
          );
        } else if (costingMethod === "Weighted Average") {
          await updateWeightedAverage(
            item,
            totalReturnQuantity,
            batchId,
            plant_id,
          );
        }
      } catch (error) {
        console.error(
          `Error updating costing for serialized item ${item.material_id}:`,
          error,
        );
        throw error;
      }
    }

    // Step 1: Update individual serial balances
    for (const balance of serialBalances) {
      const serialNumber = balance.serial_number;
      const batchId =
        materialData.item_batch_management == "1" ? balance.batch_id : null;
      const locationId = balance.location_id;
      const category =
        balance.inventory_category || balance.category || "Unrestricted";
      const returnQuantity = balance.return_quantity || balance.prt_quantity;

      console.log(
        `Processing serial balance for ${serialNumber} with quantity ${returnQuantity} in category ${category}`,
      );

      try {
        await updateSerialBalance(
          item.material_id,
          serialNumber,
          batchId,
          locationId,
          category,
          returnQuantity, // For returns, we subtract from inventory
          plant_id,
          organization_id,
        );
      } catch (error) {
        console.error(
          `Error processing serial balance for ${serialNumber}:`,
          error,
        );
        throw error;
      }
    }

    // ADDED: Update item_balance for serialized items (aggregated quantities)
    // Group by location for aggregated balance updates
    const locationGroups = new Map();

    for (const balance of serialBalances) {
      const locationId = balance.location_id;
      const returnQuantity = balance.return_quantity || balance.prt_quantity;

      if (!locationGroups.has(locationId)) {
        locationGroups.set(locationId, {
          location_id: locationId,
          total_quantity: 0,
        });
      }

      const group = locationGroups.get(locationId);
      group.total_quantity += returnQuantity;
    }

    // Update item_balance for each location (aggregated across all batches and serials)
    for (const [locationId, group] of locationGroups) {
      try {
        const generalItemBalanceParams = {
          material_id: item.material_id,
          location_id: locationId,
          plant_id: plant_id,
          organization_id: organization_id,
        };

        // Don't include batch_id in item_balance query for serialized items (aggregated balance)
        const generalBalanceQuery = await db
          .collection("item_balance")
          .where(generalItemBalanceParams)
          .get();

        if (generalBalanceQuery.data && generalBalanceQuery.data.length > 0) {
          const generalBalance = generalBalanceQuery.data[0];

          // For Purchase Return, we subtract from inventory (opposite of Goods Delivery)
          const currentUnrestrictedQty = roundQty(
            parseFloat(generalBalance.unrestricted_qty || 0),
          );
          const currentBalanceQty = roundQty(
            parseFloat(generalBalance.balance_quantity || 0),
          );

          // For Purchase Return, subtract quantities from unrestricted (default category)
          const finalUnrestrictedQty = roundQty(
            currentUnrestrictedQty - group.total_quantity,
          );
          const finalBalanceQty = roundQty(
            currentBalanceQty - group.total_quantity,
          );

          await db
            .collection("item_balance")
            .doc(generalBalance.id)
            .update({
              unrestricted_qty: Math.max(0, finalUnrestrictedQty),
              balance_quantity: Math.max(0, finalBalanceQty),
              last_updated: new Date(),
              last_transaction: allData.purchase_return_no,
            });

          console.log(
            `Updated item_balance for serialized item ${item.material_id} at ${locationId}: ` +
              `subtracted ${group.total_quantity} from aggregated balance`,
          );
        } else {
          console.warn(
            `No item_balance record found for serialized item ${item.material_id} at location ${locationId}`,
          );
        }
      } catch (error) {
        console.error(
          `Error updating item_balance for serialized item ${item.material_id} at location ${locationId}:`,
          error,
        );
        throw error;
      }
    }

    // Step 2: Group serial balances by location + batch + category for consolidated inventory movements
    const groupedBalances = new Map();

    for (const balance of serialBalances) {
      const batchId =
        materialData.item_batch_management == "1" ? balance.batch_id : null;
      const locationId = balance.location_id;
      const category =
        balance.inventory_category || balance.category || "Unrestricted";

      // Create grouping key: location + batch + category
      const groupKey = `${locationId || "no-location"}|${
        batchId || "no-batch"
      }|${category}`;

      if (!groupedBalances.has(groupKey)) {
        groupedBalances.set(groupKey, {
          location_id: locationId,
          batch_id: batchId,
          category: category,
          total_quantity: 0,
          serial_numbers: [],
        });
      }

      const group = groupedBalances.get(groupKey);
      const returnQuantity = balance.return_quantity || balance.prt_quantity;
      group.total_quantity += returnQuantity;
      group.serial_numbers.push({
        serial_number: balance.serial_number,
        quantity: returnQuantity,
      });
    }

    console.log(
      `Grouped ${serialBalances.length} serial balances into ${groupedBalances.size} consolidated inventory movements`,
    );

    // Step 3: Create consolidated inventory movements for each group
    for (const [groupKey, group] of groupedBalances) {
      console.log(
        `Creating consolidated inventory movement for group: ${groupKey}, total qty: ${group.total_quantity}`,
      );

      try {
        // Calculate pricing based on costing method
        let unitPrice = roundPrice(item.unit_price || 0);
        let totalPrice = roundPrice(item.unit_price * group.total_quantity);

        const costingMethod = materialData.material_costing_method;

        if (costingMethod === "First In First Out") {
          const fifoCostPrice = await getLatestFIFOCostPrice(
            item.material_id,
            group.batch_id,
            plant_id,
          );
          unitPrice = roundPrice(fifoCostPrice);
          totalPrice = roundPrice(fifoCostPrice * group.total_quantity);
        } else if (costingMethod === "Weighted Average") {
          const waCostPrice = await getWeightedAverageCostPrice(
            item.material_id,
            group.batch_id,
            plant_id,
          );
          unitPrice = roundPrice(waCostPrice);
          totalPrice = roundPrice(waCostPrice * group.total_quantity);
        } else if (costingMethod === "Fixed Cost") {
          const fixedCostPrice = await getFixedCostPrice(item.material_id);
          unitPrice = roundPrice(fixedCostPrice);
          totalPrice = roundPrice(fixedCostPrice * group.total_quantity);
        }

        const totalQty = roundQty(group.total_quantity);

        // Create consolidated inventory movement
        const inventoryMovementData = {
          transaction_type: "PRT",
          trx_no: allData.purchase_return_no,
          parent_trx_no: item.gr_number || allData.po_no_display,
          movement: "OUT", // Purchase return is OUT movement
          unit_price: unitPrice,
          total_price: totalPrice,
          quantity: totalQty,
          item_id: item.material_id,
          inventory_category: group.category,
          uom_id: item.return_uom_id || materialData.based_uom,
          base_qty: totalQty,
          base_uom_id: materialData.based_uom,
          bin_location_id: group.location_id,
          batch_number_id: group.batch_id,
          costing_method_id: materialData.material_costing_method,
          created_at: new Date(),
          plant_id: plant_id,
          organization_id: organization_id,
          actual_qty: -totalQty,
          actual_base_qty: -totalQty,
        };

        await db.collection("inventory_movement").add(inventoryMovementData);
        console.log(
          `Consolidated inventory movement created for group ${groupKey}`,
        );

        // Wait and fetch the created movement ID
        await new Promise((resolve) => setTimeout(resolve, 100));

        const movementQuery = await db
          .collection("inventory_movement")
          .where({
            transaction_type: "PRT",
            trx_no: allData.purchase_return_no,
            parent_trx_no: item.gr_number || allData.po_no_display,
            movement: "OUT",
            inventory_category: group.category,
            item_id: item.material_id,
            bin_location_id: group.location_id,
            base_qty: roundQty(group.total_quantity),
            plant_id: plant_id,
            organization_id: organization_id,
          })
          .get();

        if (movementQuery.data && movementQuery.data.length > 0) {
          const movementId = movementQuery.data[0].id;
          console.log(`Retrieved inventory movement ID: ${movementId}`);

          // Step 4: Create individual serial movement records for each serial in this group
          for (const serialInfo of group.serial_numbers) {
            await createSerialMovementRecord(
              movementId,
              serialInfo.serial_number,
              group.batch_id,
              serialInfo.quantity,
              materialData.based_uom,
              plant_id,
              organization_id,
            );
          }
        } else {
          console.error(
            `Failed to retrieve inventory movement for group ${groupKey}`,
          );
          throw new Error(
            `Failed to retrieve inventory movement for group ${groupKey}`,
          );
        }

        console.log(
          `Created ${group.serial_numbers.length} serial movement records for group ${groupKey}`,
        );
      } catch (groupError) {
        console.error(`Error processing group ${groupKey}:`, groupError);
        throw groupError;
      }
    }

    console.log(
      `Successfully processed ${serialBalances.length} serial balances in ${groupedBalances.size} consolidated movements for item ${item.material_id}`,
    );
  };

  if (Array.isArray(items)) {
    for (let itemIndex = 0; itemIndex < items.length; itemIndex++) {
      const item = items[itemIndex];
      console.log(
        `Processing item ${itemIndex + 1}/${items.length}: ${item.material_id}`,
      );

      try {
        // Check if item has stock control enabled
        const itemRes = await db
          .collection("Item")
          .where({ id: item.material_id })
          .get();

        if (!itemRes.data || !itemRes.data.length) {
          console.error(`Item not found: ${item.material_id}`);
          continue;
        }

        const itemData = itemRes.data[0];
        if (itemData.stock_control === 0) {
          console.log(
            `Skipping inventory update for item ${item.material_id} (stock_control=0)`,
          );
          continue;
        }

        const temporaryData = item.temp_qty_data
          ? JSON.parse(item.temp_qty_data)
          : [];
        console.log(
          `Temporary data for item ${item.material_id}:`,
          temporaryData,
        );

        // Check if item is serialized and handle accordingly
        if (isSerializedItem(itemData)) {
          console.log(
            `Item ${item.material_id} is serialized, using serial balance processing`,
          );
          try {
            await processSerializedItemReturn(
              item,
              itemData,
              temporaryData,
              plantId,
              organizationId,
              data,
            );
          } catch (error) {
            console.error(
              `Error processing serialized item ${item.material_id}:`,
              error,
            );
            throw error;
          }
          continue; // Skip regular balance processing for serialized items
        }

        if (temporaryData.length > 0) {
          for (const temp of temporaryData) {
            const itemBalanceParams = {
              material_id: item.material_id,
              location_id: temp.location_id,
            };

            // UOM Conversion
            let altQty = roundQty(temp.return_quantity);
            let baseQty = altQty;
            let altUOM = item.return_uom_id;
            let baseUOM = itemData.based_uom;
            let altWAQty = roundQty(temp.return_quantity);
            let baseWAQty = altWAQty;

            if (
              Array.isArray(itemData.table_uom_conversion) &&
              itemData.table_uom_conversion.length > 0
            ) {
              console.log(`Checking UOM conversions for item ${item.item_id}`);

              const uomConversion = itemData.table_uom_conversion.find(
                (conv) => conv.alt_uom_id === altUOM,
              );

              if (uomConversion) {
                console.log(
                  `Found UOM conversion: 1 ${uomConversion.alt_uom_id} = ${uomConversion.base_qty} ${uomConversion.base_uom_id}`,
                );

                baseQty = roundQty(altQty * uomConversion.base_qty);
                baseWAQty = roundQty(altWAQty * uomConversion.base_qty);

                console.log(
                  `Converted ${altQty} ${altUOM} to ${baseQty} ${baseUOM}`,
                );
              } else {
                console.log(
                  `No conversion found for UOM ${altUOM}, using as-is`,
                );
              }
            } else {
              console.log(
                `No UOM conversion table for item ${item.item_id}, using received quantity as-is`,
              );
            }

            const costingMethod = itemData.material_costing_method;

            let unitPrice = roundPrice(item.unit_price);
            let totalPrice = roundPrice(unitPrice * altQty);

            if (costingMethod === "First In First Out") {
              // Get unit price from latest FIFO sequence
              const fifoCostPrice = await getLatestFIFOCostPrice(
                item.material_id,
                temp.batch_id,
                plantId,
              );
              unitPrice = roundPrice(fifoCostPrice);
              totalPrice = roundPrice(fifoCostPrice * baseQty);
            } else if (costingMethod === "Weighted Average") {
              // Get unit price from WA cost price
              const waCostPrice = await getWeightedAverageCostPrice(
                item.material_id,
                temp.batch_id,
                plantId,
              );
              unitPrice = roundPrice(waCostPrice);
              totalPrice = roundPrice(waCostPrice * baseQty);
            } else if (costingMethod === "Fixed Cost") {
              // Get unit price from Fixed Cost
              const fixedCostPrice = await getFixedCostPrice(item.material_id);
              unitPrice = roundPrice(fixedCostPrice);
              totalPrice = roundPrice(fixedCostPrice * baseQty);
            } else {
              return Promise.resolve();
            }

            // Create inventory movement record
            await db.collection("inventory_movement").add({
              transaction_type: "PRT",
              trx_no: data.purchase_return_no,
              parent_trx_no: item.gr_number || data.po_no_display,
              movement: "OUT",
              unit_price: unitPrice,
              total_price: totalPrice,
              quantity: altQty,
              item_id: item.material_id,
              inventory_category: temp.inventory_category,
              uom_id: altUOM,
              base_qty: baseQty,
              base_uom_id: baseUOM,
              bin_location_id: temp.location_id,
              batch_number_id: temp.batch_id,
              costing_method_id: item.costing_method,
              plant_id: plantId,
              organization_id: organizationId,
              actual_qty: -altQty,
              actual_base_qty: -baseQty,
            });

            const categoryType = temp.inventory_category;
            const categoryValue = baseQty;

            if (temp.batch_id) {
              itemBalanceParams.batch_id = temp.batch_id;

              const batchResponse = await db
                .collection("item_batch_balance")
                .where(itemBalanceParams)
                .get();

              const batchResult = batchResponse.data;
              const hasBatchBalance =
                batchResult &&
                Array.isArray(batchResult) &&
                batchResult.length > 0;
              const existingBatchDoc = hasBatchBalance ? batchResult[0] : null;

              if (existingBatchDoc && existingBatchDoc.id) {
                let updatedUnrestrictedQty = roundQty(
                  existingBatchDoc.unrestricted_qty || 0,
                );
                let updatedQualityInspectionQty = roundQty(
                  existingBatchDoc.qualityinsp_qty || 0,
                );
                let updatedBlockQty = roundQty(existingBatchDoc.block_qty || 0);
                let updatedIntransitQty = roundQty(
                  existingBatchDoc.intransit_qty || 0,
                );

                if (categoryType === "Unrestricted") {
                  updatedUnrestrictedQty = roundQty(
                    updatedUnrestrictedQty - categoryValue,
                  );
                } else if (categoryType === "Quality Inspection") {
                  updatedQualityInspectionQty = roundQty(
                    updatedQualityInspectionQty - categoryValue,
                  );
                } else if (categoryType === "Blocked") {
                  updatedBlockQty = roundQty(updatedBlockQty - categoryValue);
                } else if (categoryType === "In Transit") {
                  updatedIntransitQty = roundQty(
                    updatedIntransitQty - categoryValue,
                  );
                }

                const updatedBalanceQty = roundQty(
                  parseFloat(existingBatchDoc.balance_quantity || 0) -
                    categoryValue,
                );

                await db
                  .collection("item_batch_balance")
                  .doc(existingBatchDoc.id)
                  .update({
                    unrestricted_qty: updatedUnrestrictedQty,
                    qualityinsp_qty: updatedQualityInspectionQty,
                    block_qty: updatedBlockQty,
                    intransit_qty: updatedIntransitQty,
                    balance_quantity: updatedBalanceQty,
                    last_updated: new Date(),
                    last_transaction: data.purchase_return_no,
                  });

                console.log(
                  `Updated batch balance for item ${item.material_id}, batch ${temp.batch_id}`,
                );

                // ADDED: Also update item_balance for batch items (aggregated balance across all batches)
                const generalItemBalanceParams = {
                  material_id: item.material_id,
                  location_id: temp.location_id,
                  plant_id: plantId,
                  organization_id: organizationId,
                };

                // Don't include batch_id in item_balance query (aggregated balance across all batches)
                const generalBalanceQuery = await db
                  .collection("item_balance")
                  .where(generalItemBalanceParams)
                  .get();

                if (
                  generalBalanceQuery.data &&
                  generalBalanceQuery.data.length > 0
                ) {
                  const generalBalance = generalBalanceQuery.data[0];

                  // Get current quantities
                  const currentGeneralUnrestrictedQty = roundQty(
                    parseFloat(generalBalance.unrestricted_qty || 0),
                  );
                  const currentGeneralQualityInspQty = roundQty(
                    parseFloat(generalBalance.qualityinsp_qty || 0),
                  );
                  const currentGeneralBlockQty = roundQty(
                    parseFloat(generalBalance.block_qty || 0),
                  );
                  const currentGeneralIntransitQty = roundQty(
                    parseFloat(generalBalance.intransit_qty || 0),
                  );
                  const currentGeneralBalanceQty = roundQty(
                    parseFloat(generalBalance.balance_quantity || 0),
                  );

                  // Apply the same category-based subtraction logic
                  let finalGeneralUnrestrictedQty =
                    currentGeneralUnrestrictedQty;
                  let finalGeneralQualityInspQty = currentGeneralQualityInspQty;
                  let finalGeneralBlockQty = currentGeneralBlockQty;
                  let finalGeneralIntransitQty = currentGeneralIntransitQty;

                  if (categoryType === "Unrestricted") {
                    finalGeneralUnrestrictedQty = roundQty(
                      currentGeneralUnrestrictedQty - categoryValue,
                    );
                  } else if (categoryType === "Quality Inspection") {
                    finalGeneralQualityInspQty = roundQty(
                      currentGeneralQualityInspQty - categoryValue,
                    );
                  } else if (categoryType === "Blocked") {
                    finalGeneralBlockQty = roundQty(
                      currentGeneralBlockQty - categoryValue,
                    );
                  } else if (categoryType === "In Transit") {
                    finalGeneralIntransitQty = roundQty(
                      currentGeneralIntransitQty - categoryValue,
                    );
                  }

                  const finalGeneralBalanceQty = roundQty(
                    currentGeneralBalanceQty - categoryValue,
                  );

                  await db
                    .collection("item_balance")
                    .doc(generalBalance.id)
                    .update({
                      unrestricted_qty: Math.max(
                        0,
                        finalGeneralUnrestrictedQty,
                      ),
                      qualityinsp_qty: Math.max(0, finalGeneralQualityInspQty),
                      block_qty: Math.max(0, finalGeneralBlockQty),
                      intransit_qty: Math.max(0, finalGeneralIntransitQty),
                      balance_quantity: Math.max(0, finalGeneralBalanceQty),
                      last_updated: new Date(),
                      last_transaction: data.purchase_return_no,
                    });

                  console.log(
                    `Updated item_balance for batch item ${item.material_id} at ${temp.location_id}: ` +
                      `subtracted ${categoryValue} from ${categoryType} (aggregated balance)`,
                  );
                } else {
                  console.warn(
                    `No item_balance record found for batch item ${item.material_id} at location ${temp.location_id}`,
                  );
                }
              } else {
                console.log(
                  `No existing item_batch_balance found for item ${item.material_id}, batch ${temp.batch_id}`,
                );
              }
            } else {
              const balanceResponse = await db
                .collection("item_balance")
                .where(itemBalanceParams)
                .get();

              const balanceResult = balanceResponse.data;
              const hasBalance =
                balanceResult &&
                Array.isArray(balanceResult) &&
                balanceResult.length > 0;
              const existingDoc = hasBalance ? balanceResult[0] : null;

              if (existingDoc && existingDoc.id) {
                let updatedUnrestrictedQty = roundQty(
                  existingDoc.unrestricted_qty || 0,
                );
                let updatedQualityInspectionQty = roundQty(
                  existingDoc.qualityinsp_qty || 0,
                );
                let updatedBlockQty = roundQty(existingDoc.block_qty || 0);
                let updatedIntransitQty = roundQty(
                  existingDoc.intransit_qty || 0,
                );

                if (categoryType === "Unrestricted") {
                  updatedUnrestrictedQty = roundQty(
                    updatedUnrestrictedQty - categoryValue,
                  );
                } else if (categoryType === "Quality Inspection") {
                  updatedQualityInspectionQty = roundQty(
                    updatedQualityInspectionQty - categoryValue,
                  );
                } else if (categoryType === "Blocked") {
                  updatedBlockQty = roundQty(updatedBlockQty - categoryValue);
                } else if (categoryType === "In Transit") {
                  updatedIntransitQty = roundQty(
                    updatedIntransitQty - categoryValue,
                  );
                }

                const updatedBalanceQty = roundQty(
                  parseFloat(existingDoc.balance_quantity || 0) - categoryValue,
                );

                await db.collection("item_balance").doc(existingDoc.id).update({
                  unrestricted_qty: updatedUnrestrictedQty,
                  qualityinsp_qty: updatedQualityInspectionQty,
                  block_qty: updatedBlockQty,
                  intransit_qty: updatedIntransitQty,
                  balance_quantity: updatedBalanceQty,
                  last_updated: new Date(),
                  last_transaction: data.purchase_return_no,
                });

                console.log(`Updated balance for item ${item.material_id}`);
              } else {
                console.log(
                  `No existing item_balance found for item ${item.material_id}`,
                );
              }
            }

            if (costingMethod === "First In First Out") {
              await updateFIFOInventory(
                item.material_id,
                baseQty,
                temp.batch_id,
                plantId,
              );
            } else if (costingMethod === "Weighted Average") {
              await updateWeightedAverage(
                item,
                baseWAQty,
                temp.batch_id,
                plantId,
              );
            } else {
              return Promise.resolve();
            }
          }
        }
      } catch (error) {
        console.error(`Error processing item ${item.material_id}:`, error);
      }
    }
  }
};

// For quantities - 3 decimal places
const roundQty = (value) => {
  return parseFloat(parseFloat(value || 0).toFixed(3));
};

// For prices - 4 decimal places
const roundPrice = (value) => {
  return parseFloat(parseFloat(value || 0).toFixed(4));
};

// Serial number validation function to prevent duplicates
const validateSerialNumbersForReturn = async (
  data,
  plantId,
  organizationId,
) => {
  console.log("Validating serial numbers for Purchase Return");

  const items = data.table_prt;
  if (!Array.isArray(items) || items.length === 0) {
    return { isValid: true };
  }

  // Helper function to safely parse JSON
  const parseJsonSafely = (jsonString, defaultValue = []) => {
    try {
      return jsonString ? JSON.parse(jsonString) : defaultValue;
    } catch (error) {
      console.error("JSON parse error:", error);
      return defaultValue;
    }
  };

  // Helper function for rounding quantities
  const roundQty = (value) => {
    return parseFloat(parseFloat(value || 0).toFixed(3));
  };

  // Create a map to track required serial numbers using pipe separator for keys
  const requiredSerialNumbers = new Map();
  const duplicateSerialNumbers = new Set();

  // First pass: Check for duplicate serial numbers within the transaction
  for (const item of items) {
    if (!item.material_id || !item.temp_qty_data) {
      continue;
    }

    try {
      // Get item data to check serialization
      const itemRes = await db
        .collection("Item")
        .where({ id: item.material_id })
        .get();

      if (!itemRes.data || !itemRes.data.length) {
        return {
          isValid: false,
          error: `Item not found: ${item.material_id}`,
        };
      }

      const itemData = itemRes.data[0];

      // Skip if not a serialized item
      if (itemData.serial_number_management !== 1) {
        continue;
      }

      const isBatchManagedItem = itemData.item_batch_management === 1;
      const temporaryData = parseJsonSafely(item.temp_qty_data);

      for (const temp of temporaryData) {
        if (!temp.serial_number) {
          continue;
        }

        const returnQuantity = temp.return_quantity || temp.prt_quantity || 0;
        if (returnQuantity <= 0) {
          continue;
        }

        // Create unique key using pipe separator to avoid conflicts with hyphens in serial numbers
        let key;
        if (isBatchManagedItem && temp.batch_id) {
          key = `${item.material_id}|${temp.location_id || "no-location"}|${
            temp.batch_id
          }|${temp.serial_number}`;
        } else {
          key = `${item.material_id}|${temp.location_id || "no-location"}|${
            temp.serial_number
          }`;
        }

        // Check for duplicates within the transaction
        if (requiredSerialNumbers.has(key)) {
          duplicateSerialNumbers.add(temp.serial_number);
          console.error(`Duplicate serial number found: ${temp.serial_number}`);
        } else {
          requiredSerialNumbers.set(key, {
            materialId: item.material_id,
            serialNumber: temp.serial_number,
            locationId: temp.location_id,
            batchId: temp.batch_id,
            returnQuantity: returnQuantity,
            itemName: itemData.material_name || item.material_id,
          });
        }
      }
    } catch (error) {
      console.error(`Error processing item ${item.material_id}:`, error);
      return {
        isValid: false,
        error: `Error processing item ${item.material_id}: ${error.message}`,
      };
    }
  }

  // Check if any duplicate serial numbers were found
  if (duplicateSerialNumbers.size > 0) {
    const duplicates = Array.from(duplicateSerialNumbers).join(", ");
    return {
      isValid: false,
      error: `Duplicate serial numbers detected within transaction: ${duplicates}. Each serial number can only be returned once.`,
    };
  }

  // Second pass: Check availability against current inventory balances
  for (const [key, serialInfo] of requiredSerialNumbers.entries()) {
    try {
      // Check if the serial number exists in inventory
      const serialBalanceParams = {
        material_id: serialInfo.materialId,
        serial_number: serialInfo.serialNumber,
        plant_id: plantId,
        organization_id: organizationId,
        location_id: serialInfo.locationId,
      };

      if (serialInfo.batchId) {
        serialBalanceParams.batch_id = serialInfo.batchId;
      }

      if (serialInfo.locationId && serialInfo.locationId !== "no-location") {
        serialBalanceParams.location_id = serialInfo.locationId;
      }

      const balanceQuery = await db
        .collection("item_serial_balance")
        .where(serialBalanceParams)
        .get();

      if (!balanceQuery.data || balanceQuery.data.length === 0) {
        return {
          isValid: false,
          error: `Serial number "${serialInfo.serialNumber}" not found in inventory for item "${serialInfo.itemName}".`,
        };
      }

      const balance = balanceQuery.data[0];
      const totalAvailableQty = roundQty(
        parseFloat(balance.unrestricted_qty || 0) +
          parseFloat(balance.reserved_qty || 0) +
          parseFloat(balance.qualityinsp_qty || 0) +
          parseFloat(balance.block_qty || 0),
      );

      // For serialized items, total quantity should typically be 1
      // But check if sufficient quantity is available for return
      if (totalAvailableQty < serialInfo.returnQuantity) {
        let errorMsg = `Insufficient inventory for serial number "${serialInfo.serialNumber}" of item "${serialInfo.itemName}". `;
        errorMsg += `Required: ${serialInfo.returnQuantity}, Available: ${totalAvailableQty}`;

        if (serialInfo.locationId && serialInfo.locationId !== "no-location") {
          try {
            const locationRes = await db
              .collection("bin_location")
              .where({ id: serialInfo.locationId })
              .get();

            const locationName =
              locationRes.data && locationRes.data.length > 0
                ? locationRes.data[0].bin_location_combine ||
                  serialInfo.locationId
                : serialInfo.locationId;

            errorMsg += `, Location: "${locationName}"`;
          } catch {
            errorMsg += `, Location: "${serialInfo.locationId}"`;
          }
        }

        if (serialInfo.batchId) {
          try {
            const batchRes = await db
              .collection("batch")
              .where({ id: serialInfo.batchId })
              .get();

            const batchName =
              batchRes.data && batchRes.data.length > 0
                ? batchRes.data[0].batch_number || serialInfo.batchId
                : serialInfo.batchId;

            errorMsg += `, Batch: "${batchName}"`;
          } catch {
            errorMsg += `, Batch: "${serialInfo.batchId}"`;
          }
        }

        return {
          isValid: false,
          error: errorMsg,
        };
      }

      console.log(
        `Serial number validation passed for ${serialInfo.serialNumber}: Available=${totalAvailableQty}, Required=${serialInfo.returnQuantity}`,
      );
    } catch (error) {
      console.error(`Error checking serial balance for ${key}:`, error);
      return {
        isValid: false,
        error: `Error checking serial number availability: ${error.message}`,
      };
    }
  }

  console.log(
    `Serial number validation passed for Purchase Return with ${requiredSerialNumbers.size} unique serial numbers`,
  );
  return { isValid: true };
};

