    let newData = getOpData?.length> 0? getOpData:optionsData;
      const newOptionsData = [{label: 'Manual Input', value: -9999}, ...newData];
      this.setOptionData("purchase_return_no_type", newOptionsData);
  }, 200)
}

const { value } = arguments[0];
this.setData({
  purchase_return_no: ''
});
if(value === -9999) {
   this.disabled('purchase_return_no', false)
} else {
   this.disabled('purchase_return_no', true)
}

